import { useState } from "react";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import { useAppStore } from "../store/appStore";
import V2EmptyState from "../components/V2EmptyState";

/* ── helpers ─────────────────────────────────────────── */
const fmtPct = (v) => v == null ? "--" : `${(v * 100).toFixed(1)}%`;
const fmtMs  = (v) => v == null ? "--" : `${v.toFixed(0)}ms`;
const ago = (ts) => {
  if (!ts) return "--";
  const d = Date.now() - new Date(ts).getTime();
  if (d < 60000) return `${Math.floor(d / 1000)}s ago`;
  if (d < 3600000) return `${Math.floor(d / 60000)}m ago`;
  return `${Math.floor(d / 3600000)}h ago`;
};

/* ── stat card ───────────────────────────────────────── */
function Stat({ label, value, tone = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${tone}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* ── venue colors ────────────────────────────────────── */
const VENUE_COLORS = [
  "rgba(110,240,180,0.7)", "rgba(150,190,255,0.7)", "rgba(255,210,120,0.7)",
  "rgba(200,140,255,0.7)", "rgba(255,140,140,0.7)", "rgba(100,220,220,0.7)",
];

/* ── main page ───────────────────────────────────────── */
export default function SOR() {
  const { state } = useAppStore();
  const [priorities, setPriorities] = useState(["SMART", "IEX", "BATS", "ARCA", "NYSE", "EDGX"]);
  const [minFillSize, setMinFillSize] = useState(100);
  const [maxDarkPct, setMaxDarkPct] = useState(15);

  /* poll execution quality for venue data */
  const { data: eqData, loading } = usePoll(
    async () => { const r = await http.get("/v2/execution-quality"); return r.data; },
    { intervalMs: 10000, enabled: !state.offlineMode }
  );

  /* poll routing decision journal (endpoint may not exist yet) */
  const { data: journal } = usePoll(
    async () => {
      try { const r = await http.get("/exec/journal"); return r.data; }
      catch { return null; }
    },
    { intervalMs: 30000, enabled: !state.offlineMode }
  );

  const byVenue = eqData?.by_venue ?? [];
  const summary = eqData?.summary ?? null;
  const decisions = Array.isArray(journal) ? journal : journal?.decisions ?? [];

  /* derived stats */
  const activeVenues = byVenue.length;
  const routingScore = summary?.routing_score ?? null;
  const nbboRate = summary?.nbbo_compliance ?? summary?.nbbo_rate ?? null;
  const darkPct = summary?.dark_pool_pct ?? null;
  const totalVolume = byVenue.reduce((a, v) => a + (v.volume ?? v.fills ?? 0), 0);

  const moveUp = (idx) => {
    if (idx === 0) return;
    const next = [...priorities];
    [next[idx - 1], next[idx]] = [next[idx], next[idx - 1]];
    setPriorities(next);
  };

  const moveDown = (idx) => {
    if (idx === priorities.length - 1) return;
    const next = [...priorities];
    [next[idx], next[idx + 1]] = [next[idx + 1], next[idx]];
    setPriorities(next);
  };

  return (
    <>
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Smart Order Routing</h1>
          <div className="v2-muted">Venue analysis, routing decisions, best-execution rationale.</div>
        </div>
        <div className="v2-row">
          <span className="v2-pill v2-mono">{totalVolume.toLocaleString()} orders</span>
          <span className="v2-pill">Live</span>
        </div>
      </div>

      {loading ? (
        <div className="v2-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      ) : (
        <>
          {/* ── Top Stats ────────────────────────────────── */}
          <div className="v2-grid" style={{ marginBottom: 16 }}>
            <Stat label="Active Venues" value={activeVenues > 0 ? activeVenues : "--"} tone={activeVenues >= 4 ? "green" : "amber"} sub={activeVenues > 0 ? "Receiving fills" : "No venue data yet"} />
            <Stat label="Routing Score" value={routingScore != null ? `${routingScore}/100` : "--"} tone={routingScore != null ? (routingScore > 90 ? "green" : routingScore > 70 ? "amber" : "red") : "blue"} sub={routingScore != null ? "Best execution quality" : "Waiting for data"} />
            <Stat label="NBBO Compliance" value={nbboRate != null ? fmtPct(nbboRate) : "--"} tone={nbboRate != null ? (nbboRate > 0.95 ? "green" : "amber") : "blue"} sub={nbboRate != null ? "At or better than NBBO" : "Waiting for data"} />
            <Stat label="Dark Pool %" value={darkPct != null ? fmtPct(darkPct) : "--"} tone={darkPct != null ? (darkPct < 0.20 ? "green" : "amber") : "blue"} sub={darkPct != null ? "Of total volume" : "Waiting for data"} />
          </div>

          <div className="v2-grid">
            {/* ── Venue Breakdown Table ────────────────────── */}
            <div className="v2-card wide">
              <div className="v2-ct">Venue Breakdown</div>
              {byVenue.length === 0 ? (
                <V2EmptyState icon={"\u29C6"} title="No Venue Data" message="Venue breakdown will appear when order routing data is available from the API." />
              ) : (
                <div className="v2-table" style={{ marginTop: 8 }}>
                  <div className="v2-thead" style={{ gridTemplateColumns: "120px 100px 100px 100px 100px 100px 80px" }}>
                    <span>Venue</span>
                    <span>Volume</span>
                    <span>Fill Rate</span>
                    <span>Avg Slippage</span>
                    <span>Avg Latency</span>
                    <span>Rebate</span>
                    <span>Type</span>
                  </div>
                  {byVenue.map(v => {
                    const rate = v.fill_rate ?? (v.fills && v.orders ? v.fills / v.orders : null);
                    return (
                      <div key={v.venue} className="v2-tr" style={{ gridTemplateColumns: "120px 100px 100px 100px 100px 100px 80px" }}>
                        <span style={{ fontWeight: 600 }}>{v.venue}</span>
                        <span className="v2-mono">{(v.volume ?? v.fills ?? 0).toLocaleString()}</span>
                        <span className={`v2-mono v2-${rate != null && rate > 0.95 ? "green" : "amber"}`}>{rate != null ? fmtPct(rate) : "--"}</span>
                        <span className="v2-mono v2-muted">{v.avg_slippage_bps != null ? `${v.avg_slippage_bps.toFixed(1)} bps` : "--"}</span>
                        <span className="v2-mono v2-muted">{v.avg_latency_ms != null ? fmtMs(v.avg_latency_ms) : "--"}</span>
                        <span className="v2-mono v2-muted">{v.rebate != null ? `$${v.rebate.toFixed(4)}` : "--"}</span>
                        <span className={`v2-${v.is_dark ? "amber" : "blue"}`} style={{ fontSize: 11, fontWeight: 600 }}>
                          {v.is_dark ? "DARK" : "LIT"}
                        </span>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>

            {/* ── Routing Decision Log ────────────────────── */}
            <div className="v2-card wide">
              <div className="v2-ct">Routing Decision Log</div>
              {decisions.length === 0 ? (
                <V2EmptyState icon={"\u29C6"} title="No Routing Log" message="Routing decisions will appear when the SOR engine reports routing rationale." />
              ) : (
                <div className="v2-table" style={{ marginTop: 8 }}>
                  <div className="v2-thead" style={{ gridTemplateColumns: "100px 80px 80px 100px 80px 1fr" }}>
                    <span>Time</span>
                    <span>Symbol</span>
                    <span>Side</span>
                    <span>Venue</span>
                    <span>Qty</span>
                    <span>Rationale</span>
                  </div>
                  {decisions.slice(0, 20).map((d, i) => (
                    <div key={i} className="v2-tr" style={{ gridTemplateColumns: "100px 80px 80px 100px 80px 1fr" }}>
                      <span className="v2-mono v2-muted">{ago(d.timestamp ?? d.ts)}</span>
                      <span style={{ fontWeight: 600 }}>{d.symbol ?? "--"}</span>
                      <span className={`v2-${d.side === "BUY" ? "green" : "red"}`} style={{ fontWeight: 600, fontSize: 11 }}>
                        {d.side ?? "--"}
                      </span>
                      <span className="v2-mono">{d.venue ?? "--"}</span>
                      <span className="v2-mono">{d.qty ?? d.quantity ?? "--"}</span>
                      <span className="v2-muted" style={{ fontSize: 11 }}>{d.rationale ?? d.reason ?? "--"}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* ── Venue Distribution ────────────────────── */}
            <div className="v2-card half">
              <div className="v2-ct">Venue Distribution</div>
              {byVenue.length === 0 ? (
                <V2EmptyState icon={"\u29C6"} title="No Distribution Data" message="Venue distribution chart will appear when order data is available." />
              ) : (
                <div style={{ marginTop: 12 }}>
                  {/* stacked bar */}
                  <div style={{ display: "flex", height: 28, borderRadius: 6, overflow: "hidden", background: "rgba(255,255,255,0.04)" }}>
                    {byVenue.map((v, i) => {
                      const vol = v.volume ?? v.fills ?? 0;
                      const pct = totalVolume > 0 ? (vol / totalVolume) * 100 : 0;
                      return (
                        <div key={v.venue} style={{
                          width: `${pct}%`, background: VENUE_COLORS[i % VENUE_COLORS.length],
                          display: "flex", alignItems: "center", justifyContent: "center",
                          fontSize: 10, fontWeight: 600, overflow: "hidden", whiteSpace: "nowrap",
                        }} title={`${v.venue}: ${vol.toLocaleString()} (${pct.toFixed(1)}%)`}>
                          {pct > 10 ? v.venue : ""}
                        </div>
                      );
                    })}
                  </div>
                  {/* legend */}
                  <div style={{ marginTop: 12 }}>
                    {byVenue.map((v, i) => {
                      const vol = v.volume ?? v.fills ?? 0;
                      const pct = totalVolume > 0 ? ((vol / totalVolume) * 100).toFixed(1) : "0";
                      return (
                        <div key={v.venue} style={{
                          display: "flex", justifyContent: "space-between", alignItems: "center",
                          padding: "4px 0", fontSize: 13,
                        }}>
                          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                            <span style={{ width: 10, height: 10, borderRadius: 6, background: VENUE_COLORS[i % VENUE_COLORS.length], display: "inline-block" }} />
                            <span>{v.venue}</span>
                          </div>
                          <div>
                            <span className="v2-mono">{vol.toLocaleString()}</span>
                            <span className="v2-muted" style={{ marginLeft: 4 }}>({pct}%)</span>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}
            </div>

            {/* ── Routing Policy Editor ───────────────────── */}
            <div className="v2-card half">
              <div className="v2-ct">Routing Policy</div>
              <div style={{ marginBottom: 12 }}>
                <div className="v2-muted" style={{ marginBottom: 8 }}>Venue Priority Order</div>
                <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                  {priorities.map((v, i) => (
                    <div key={v} className="v2-row" style={{
                      padding: "6px 10px", borderRadius: 10,
                      background: "rgba(255,255,255,0.04)",
                      border: "1px solid var(--v2-border)",
                      justifyContent: "space-between",
                    }}>
                      <span style={{ fontSize: 13 }}>
                        <span className="v2-mono v2-muted" style={{ marginRight: 8 }}>{i + 1}.</span>
                        {v}
                      </span>
                      <div className="v2-row" style={{ gap: 4 }}>
                        <button className="v2-btn" style={{ padding: "2px 8px", fontSize: 11 }}
                          onClick={() => moveUp(i)} disabled={i === 0}>
                          Up
                        </button>
                        <button className="v2-btn" style={{ padding: "2px 8px", fontSize: 11 }}
                          onClick={() => moveDown(i)} disabled={i === priorities.length - 1}>
                          Dn
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
              <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
                <div style={{ flex: 1, minWidth: 120 }}>
                  <div className="v2-muted" style={{ marginBottom: 4, fontSize: 11 }}>Min Fill Size</div>
                  <input className="v2-input v2-mono" type="number" value={minFillSize}
                    onChange={(e) => setMinFillSize(Number(e.target.value))}
                    style={{ width: "100%" }}
                  />
                </div>
                <div style={{ flex: 1, minWidth: 120 }}>
                  <div className="v2-muted" style={{ marginBottom: 4, fontSize: 11 }}>Max Dark Pool %</div>
                  <input className="v2-input v2-mono" type="number" value={maxDarkPct}
                    onChange={(e) => setMaxDarkPct(Number(e.target.value))}
                    style={{ width: "100%" }}
                  />
                </div>
              </div>
            </div>
          </div>
        </>
      )}
    </>
  );
}
